// be parked instead of retried immediately.
type ParkingOutcome struct {
	Unclaim              bool
	RetryAfter           time.Time
	RunPostAttemptTriage bool
	Event                *ParkingEvent
}

// ParkingEvent is the event template returned by Attempt for structured park
// outcomes. The execute loop converts it into a bead.BeadEvent when it applies
// the parking instructions.
type ParkingEvent struct {
	Kind    string
	Summary string
	Body    string
}

func Attempt(ctx context.Context, store Store, beadID string, opts AttemptOpts) (Outcome, error) {
	if opts.Executor == nil {
		return Outcome{}, fmt.Errorf("try attempt: executor is required")
	}
	rateCfg := resolveRateLimitRetryConfig(opts)
	var (
		report Report
		err    error
	)
	for retryCount, elapsed := 0, time.Duration(0); ; {
		report, err = opts.Executor.Execute(ctx, beadID)
		if err != nil {
			report = Report{
				BeadID: beadID,
				Status: StatusExecutionFailed,
				Detail: err.Error(),
				Error:  err.Error(),
			}
		}
		if report.BeadID == "" {
			report.BeadID = beadID
		}
		if report.Status == "" {
			report.Status = StatusExecutionFailed
		}
		if ctx != nil && ctx.Err() != nil {
			if err == nil {
				err = ctx.Err()
			}
			if report.Error == "" {
				report.Error = ctx.Err().Error()
			}
			if report.Detail == "" {
				report.Detail = ctx.Err().Error()
			}
			return Outcome{Report: report, Disposition: OutcomeReported}, err
		}

		rateLimited := IsRateLimitReport(&report)
		effectiveBudget := rateCfg.Budget
		if opts.RateLimitBudget == 0 && report.RateLimitBudget != 0 {
			effectiveBudget = report.RateLimitBudget
		}
		decision, retryAfter := evaluateRateLimitAttempt(report, rateCfg, retryCount+1, elapsed, effectiveBudget)
		if !decision.ShouldRetry {
			if decision.Reason != "" {
				report.Error = decision.Reason
			}
			if rateLimited && decision.Reason != "" && rateCfg.OnRetry != nil {
				rateCfg.OnRetry(ctx, RateLimitRetryInfo{
					Attempt:    retryCount + 1,
					Source:     decision.Source,
					Report:     &report,
					Elapsed:    elapsed,
					RetryAfter: retryAfter,
					OverBudget: true,
				})
			}
			break
		}

		retryCount++
		info := RateLimitRetryInfo{
			Attempt:    retryCount,

			Attempt:    retryCount,
			Wait:       decision.Wait,
			Source:     decision.Source,
			Report:     &report,
			Elapsed:    elapsed,
			RetryAfter: retryAfter,
		}
		if rateCfg.OnRetry != nil {
			rateCfg.OnRetry(ctx, info)
		}
		if err := rateCfg.Sleep(ctx, decision.Wait); err != nil {
			return Outcome{}, err
		}
		elapsed += decision.Wait
	}

	if ShouldAttemptConflictRecovery(report, opts.ProjectRoot) {
		if opts.Store == nil {
			opts.Store = store
		}
		return ConflictRecoveryOutcome(ctx, ConflictRecoveryInput{
			Bead:             opts.Bead,
			Report:           report,
			ProjectRoot:      opts.ProjectRoot,
			AutoRecover:      opts.AutoRecover,
			ConflictResolver: opts.ConflictResolver,
			Store:            opts.Store,
			Assignee:         opts.Assignee,
			Now:              opts.Now,
			Cooldown:         opts.Cooldown,
		}), err
	}

	if report.Status == StatusNoChanges {
		if opts.Store == nil {
			opts.Store = store
		}
		if opts.Store == nil {
			return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: fmt.Errorf("try attempt: no_changes store is required")}, nil
		}
		noChangesCount, countErr := opts.Store.IncrNoChangesCount(beadID)
		if countErr != nil {
			return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: countErr}, nil
		}
		report.EscalationCount = noChangesCount
		noChangesOut, adjudicatedReport, adjErr := adjudicateNoChangesContract(ctx, beadID, report, opts.ProjectRoot, noChangesCount, opts.SatisfactionChecker, opts.VerificationRunner)
		if adjErr != nil {
			return Outcome{Report: report, StoreErrOp: "adjudicateNoChanges", StoreErr: adjErr}, nil
		}
		return Outcome{
			Report:      adjudicatedReport,
			Disposition: OutcomeReported,
			NoChanges:   &noChangesOut,
		}, nil
	}

	if report.Status == StatusDeclinedNeedsDecomposition {
		effectiveStore := opts.Store
		if effectiveStore == nil {
			effectiveStore = store
		}
		if effectiveStore != nil {
			if err := effectiveStore.UpdateWithLifecycleStatus(beadID, bead.StatusOpen, bead.LifecycleTransitionOptions{
				Reason: "declined: bead requires decomposition before execution",
				Source: "legacy agent try",
			}, func(b *bead.Bead) error {
				if b.Extra == nil {
					b.Extra = make(map[string]any)
				}
				b.Extra[bead.ExtraExecutionElig] = false
				return nil
			}); err != nil {
				return Outcome{Report: report, StoreErrOp: "UpdateWithLifecycleStatus", StoreErr: err}, nil
			}
		}
		event := buildDecompositionParkingEvent(report)
		return Outcome{
			Report:      report,
			Disposition: OutcomePark,
			Parking: &ParkingOutcome{
				Unclaim:              true,
				RunPostAttemptTriage: true,
				Event:                event,
			},
		}, nil
	}

	if report.Status == StatusPushConflict {
		parkUntil := nowFn(opts.Now).UTC().Add(maxAttemptCooldown)
		report.RetryAfter = parkUntil.Format(time.RFC3339)
		event := buildPushConflictParkingEvent(report)
		return Outcome{
			Report:      report,
			Disposition: OutcomePark,
			Parking: &ParkingOutcome{
				Unclaim:              true,
				RetryAfter:           parkUntil,
				RunPostAttemptTriage: true,
				Event:                event,
			},
		}, nil
	}

	return Outcome{Report: report, Disposition: OutcomeReported}, err
}

func nowFn(fn func() time.Time) time.Time {
	if fn != nil {
		return fn()
	}
	return time.Now()
}

const maxAttemptCooldown = 24 * time.Hour

func buildDecompositionParkingEvent(report Report) *ParkingEvent {
	body, mErr := json.Marshal(map[string]any{
		"rationale":            report.DecompositionRationale,
		"recommended_subbeads": report.DecompositionRecommendation,
		"detail":               report.Detail,
		"base_rev":             report.BaseRev,
		"session_id":           report.SessionID,
	})
	bodyStr := ""
	if mErr == nil {
		bodyStr = string(body)
	} else {
		bodyStr = fmt.Sprintf("rationale=%s\nrecommended_subbeads=%v",
			report.DecompositionRationale, report.DecompositionRecommendation)
	}
	summary := "agent declined: needs decomposition"
	if n := len(report.DecompositionRecommendation); n > 0 {
		summary = fmt.Sprintf("%s (%d sub-beads)", summary, n)
	}
	return &ParkingEvent{
		Kind:    "decomposition-recommendation",
		Summary: summary,
		Body:    bodyStr,
	}
}

func buildPushConflictParkingEvent(report Report) *ParkingEvent {
	body, mErr := json.Marshal(map[string]any{
		"detail":     report.Detail,
		"base_rev":   report.BaseRev,
		"result_rev": report.ResultRev,
		"session_id": report.SessionID,
	})
	bodyStr := report.Detail
	if mErr == nil {
		bodyStr = string(body)
	}
	return &ParkingEvent{
		Kind:    "push-conflict",
		Summary: "auto-merge after push race could not be resolved",
		Body:    bodyStr,
	}
}

type RateLimitRetryConfig struct {
	Budget     time.Duration
	PerWaitCap time.Duration
	Sleep      func(ctx context.Context, d time.Duration) error
	Now        func() time.Time
	Evaluator  func(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision
	OnRetry    func(ctx context.Context, info RateLimitRetryInfo)
}

const (
	RateLimitRetryDefaultBudget     = 5 * time.Minute
	RateLimitRetryDefaultPerWaitCap = 60 * time.Second
	RateLimitBudgetExhaustedReason  = "rate-limited beyond budget"
)

var rateLimitBackoffSchedule = []time.Duration{
	1 * time.Second,
	5 * time.Second,
	15 * time.Second,
	30 * time.Second,
	60 * time.Second,
}

type RateLimitWaitDecision struct {
	ShouldRetry bool
	Wait        time.Duration
	Source      string
	Reason      string
}

type RateLimitRetryInfo struct {
	Attempt    int
	Wait       time.Duration
	Source     string
	Report     *Report
	Elapsed    time.Duration
	RetryAfter time.Duration
	OverBudget bool
}

func resolveRateLimitRetryConfig(opts AttemptOpts) RateLimitRetryConfig {
	cfg := RateLimitRetryConfig{
		Budget:     opts.RateLimitBudget,
		PerWaitCap: opts.RateLimitPerWaitCap,
		Evaluator:  opts.RateLimitWaitEvaluator,
		Sleep:      opts.RateLimitSleep,
		Now:        opts.RateLimitNow,
		OnRetry:    opts.RateLimitOnRetry,
	}
	if cfg.Budget == 0 {
		cfg.Budget = RateLimitRetryDefaultBudget
	}
	if cfg.PerWaitCap == 0 {
		cfg.PerWaitCap = RateLimitRetryDefaultPerWaitCap
	}
	if cfg.Sleep == nil {
		cfg.Sleep = ctxSleep
	}
	if cfg.Now == nil {
		cfg.Now = time.Now
	}
	if cfg.Evaluator == nil {
		cfg.Evaluator = EvaluateRateLimitWait
	}
	return cfg
}

func ctxSleep(ctx context.Context, d time.Duration) error {
	if d <= 0 {
		return nil
	}
	t := time.NewTimer(d)
	defer t.Stop()
	select {
	case <-ctx.Done():
		return ctx.Err()
	case <-t.C:
		return nil
	}
}

func evaluateRateLimitAttempt(report Report, cfg RateLimitRetryConfig, attempt int, elapsed, budget time.Duration) (RateLimitWaitDecision, time.Duration) {
	if cfg.Budget < 0 || budget < 0 {
		return RateLimitWaitDecision{ShouldRetry: false}, 0
	}
	if !IsRateLimitReport(&report) {
		return RateLimitWaitDecision{ShouldRetry: false}, 0
	}

	retryAfter := ExtractRetryAfterFromStderr(report.Stderr, cfg.Now())
	decision := cfg.Evaluator(retryAfter, attempt, elapsed, budget, cfg.PerWaitCap)
	if !decision.ShouldRetry {
		decision.Reason = RateLimitBudgetExhaustedReason
	}
	return decision, retryAfter
}

func EvaluateRateLimitWait(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision {
	if budget > 0 && elapsed >= budget {
		return RateLimitWaitDecision{ShouldRetry: false, Reason: RateLimitBudgetExhaustedReason}
	}

	var wait time.Duration
	var source string
	if retryAfter > 0 {
		wait = retryAfter
		source = "retry-after"
	} else {
		idx := attempt - 1
		if idx < 0 {
			idx = 0
		}
		if idx >= len(rateLimitBackoffSchedule) {
			idx = len(rateLimitBackoffSchedule) - 1
		}
		wait = rateLimitBackoffSchedule[idx]
		source = "exponential-backoff"
	}

	if perWaitCap > 0 && wait > perWaitCap {
		wait = perWaitCap
	}

	if budget > 0 && elapsed+wait > budget {
		remaining := budget - elapsed
		if remaining <= 0 {
			return RateLimitWaitDecision{ShouldRetry: false, Reason: RateLimitBudgetExhaustedReason}
		}
		wait = remaining
	}

	return RateLimitWaitDecision{ShouldRetry: true, Wait: wait, Source: source}
}

func IsRateLimitReport(report *Report) bool {
	if report == nil {
		return false
	}
	combined := strings.ToLower(report.Error + "\n" + report.Stderr + "\n" + report.Detail)
	if combined == "\n\n" {
		return false
	}
	if strings.Contains(combined, "quota exceeded") ||
		strings.Contains(combined, "insufficient quota") ||
		strings.Contains(combined, "no viable provider") {
		return false
	}
	if strings.Contains(combined, "rate limit") || strings.Contains(combined, "ratelimit") {
		return true
	}
	return hasIsolated429(combined)
}

func hasIsolated429(s string) bool {
	for i := 0; i+3 <= len(s); i++ {
		if s[i:i+3] != "429" {
			continue
		}
		if i > 0 {
			c := s[i-1]
			if c >= '0' && c <= '9' {
				continue
			}
		}
		if i+3 < len(s) {
			c := s[i+3]
			if c >= '0' && c <= '9' {
				continue
			}
		}
		return true
	}
	return false
}

func ParseRetryAfter(value string, now time.Time) time.Duration {
	value = strings.TrimSpace(value)
	if value == "" {
		return 0
	}
	if secs, err := strconv.Atoi(value); err == nil {
		if secs < 0 {
			return 0
		}
		return time.Duration(secs) * time.Second
	}
	if t, err := http.ParseTime(value); err == nil {
		d := t.Sub(now)
		if d < 0 {
			return 0
		}
		return d
	}
	if d, err := time.ParseDuration(value); err == nil && d >= 0 {
		return d
	}
	return 0
}

func ExtractRetryAfterFromStderr(stderr string, now time.Time) time.Duration {
	if stderr == "" {
		return 0
	}
	lower := strings.ToLower(stderr)
	for _, marker := range []string{"retry-after:", "retry_after=", "retry-after ", "retry after "} {
		idx := strings.Index(lower, marker)
		if idx < 0 {
			continue
		}
		rest := stderr[idx+len(marker):]
		if eol := strings.IndexAny(rest, "\r\n"); eol >= 0 {
			rest = rest[:eol]
		}
		rest = strings.TrimSpace(rest)
		rest = strings.Trim(rest, "\"',")
		if d := ParseRetryAfter(rest, now); d > 0 {
			return d
		}
	}
	return 0
}

func ShouldAttemptConflictRecovery(report Report, projectRoot string) bool {
	if report.PreserveRef == "" || projectRoot == "" {
		return false
	}
	switch report.Status {
	case StatusLandConflict:
		return true
	case StatusExecutionFailed:
		return report.BaseRev != "" && report.ResultRev != "" && report.ResultRev != report.BaseRev
	}
	return false
}

	PerWaitCap time.Duration
	// Sleep is the function the wrapper calls between attempts. Defaults to
	// a context-aware time.Sleep. Tests inject a fake to avoid real waits.
	Sleep func(ctx context.Context, d time.Duration) error
	// Now returns the current time for HTTP-date arithmetic. Defaults to
	// time.Now.
	Now func() time.Time
	// OnRetry, when non-nil, is invoked after each wait + before the retry
	// attempt fires. Used by integration to emit the rate-limit-retry bead
	// event and the routing-engine RecordRouteAttempt feedback.
	OnRetry func(ctx context.Context, info RateLimitRetryInfo)
}

// RateLimitRetryInfo describes one rate-limit retry event for telemetry hooks.
type RateLimitRetryInfo struct {
	Attempt    int
	Wait       time.Duration
	Source     string
	Result     *Result
	Elapsed    time.Duration
	OverBudget bool
}

// resolved returns a copy of cfg with zero fields filled in from defaults.
func (cfg RateLimitRetryConfig) resolved() RateLimitRetryConfig {
	out := cfg
	if out.Budget == 0 {
		out.Budget = RateLimitRetryDefaultBudget
	}
	if out.PerWaitCap == 0 {
		out.PerWaitCap = RateLimitRetryDefaultPerWaitCap
	}
	if out.Sleep == nil {
		out.Sleep = ctxSleep
	}
	if out.Now == nil {
		out.Now = time.Now
	}
	return out
}

func ctxSleep(ctx context.Context, d time.Duration) error {
	if d <= 0 {
		return nil
	}
	t := time.NewTimer(d)
	defer t.Stop()
	select {
	case <-ctx.Done():
		return ctx.Err()
	case <-t.C:
		return nil
	}
}

// RunWithRateLimitRetry invokes attempt and, when its result is a rate-limit
// signal per IsRateLimitResult, waits per EvaluateRateLimitWait and retries
// until either attempt returns a non-rate-limit result or the per-bead budget
// is exhausted. Budget exhaustion mutates the final result's Error to
// RateLimitBudgetExhaustedReason and returns it without further retries.
//
// The wrapper does NOT change provider availability state — the provider
// stays in rotation per AC #2 of ddx-c6e3db02. Per AC #6, callers wire
// RecordRouteAttempt via OnRetry for transparency.
func RunWithRateLimitRetry(ctx context.Context, cfg RateLimitRetryConfig, attempt func(ctx context.Context) (*Result, error)) (*Result, error) {
	if cfg.Budget < 0 {
		// Negative budget disables the wrapper entirely (parity with
		// "feature off"). Useful for tests and operator opt-out.
		return attempt(ctx)
	}
	cfg = cfg.resolved()

	var (
		elapsed    time.Duration
		retryCount int
	)
	for {
		res, err := attempt(ctx)
		if err != nil || res == nil {
			return res, err
		}
		if !IsRateLimitResult(res) {
			return res, nil
		}

		retryCount++
		retryAfter := ExtractRetryAfterFromStderr(res.Stderr, cfg.Now())
		decision := EvaluateRateLimitWait(retryAfter, retryCount, elapsed, cfg.Budget, cfg.PerWaitCap)
		if !decision.ShouldRetry {
			// Budget exhausted: surface the canonical reason so the standard
			// execution_failed mapping fires (TD-031 §5).
			res.Error = RateLimitBudgetExhaustedReason
			if cfg.OnRetry != nil {
				cfg.OnRetry(ctx, RateLimitRetryInfo{
					Attempt:    retryCount,
					Source:     decision.Source,
					Result:     res,
					Elapsed:    elapsed,
					OverBudget: true,
				})
			}
			return res, nil
		}

		if cfg.OnRetry != nil {
			cfg.OnRetry(ctx, RateLimitRetryInfo{
				Attempt: retryCount,
				Wait:    decision.Wait,
				Source:  decision.Source,
				Result:  res,
				Elapsed: elapsed,
			})
		}

		if err := cfg.Sleep(ctx, decision.Wait); err != nil {
			return res, err
		}
		elapsed += decision.Wait
	}
}

// BuildRateLimitRouteAttempt constructs a fizeau.RouteAttempt that records a
// rate-limit retry on the routing-engine feedback channel. The Status is
// "rate_limited" so the engine has signal even though provider availability
// remains unchanged per RateLimitRetryContract.
func BuildRateLimitRouteAttempt(info RateLimitRetryInfo) agentlib.RouteAttempt {
	att := agentlib.RouteAttempt{
		Status:    "rate_limited",
		Reason:    info.Source,
		Duration:  info.Wait,
		Timestamp: time.Now().UTC(),
	}
	if info.Result != nil {
		att.Harness = info.Result.Harness
		att.Provider = info.Result.Provider
		att.Model = info.Result.Model
		att.Error = info.Result.Error
	}
	if info.OverBudget {
		att.Reason = RateLimitBudgetExhaustedReason
	}
	return att
}

